import type {
  BreadcrumbCompactEmits,
  BreadcrumbCompactProps,
  BreadcrumbCompactSlots,
  BreadcrumbOptionData,
  BreadcrumbUi
} from '@soybeanjs/headless/breadcrumb';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Breadcrumb component.
 */
export interface BreadcrumbProps<
  T extends BreadcrumbOptionData = BreadcrumbOptionData
> extends BreadcrumbCompactProps<T> {
  /**
   * root class
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<BreadcrumbUi>;
}

/**
 * Events for the Breadcrumb component.
 */
export type BreadcrumbEmits<T extends BreadcrumbOptionData = BreadcrumbOptionData> = BreadcrumbCompactEmits<T>;

/**
 * Slots for the Breadcrumb component.
 */
export type BreadcrumbSlots<T extends BreadcrumbOptionData = BreadcrumbOptionData> = BreadcrumbCompactSlots<T>;

export type { BreadcrumbOptionData } from '@soybeanjs/headless/breadcrumb';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const breadcrumbVariants = scv({
  slots: {
    root: '',
    list: 'flex flex-wrap items-center my-0 px-0 break-words text-muted-foreground',
    item: 'inline-flex items-center list-none',
    page: 'font-normal text-foreground',
    separator: 'text-muted-foreground flex-shrink-0 list-none',
    ellipsis: 'flex items-center justify-center',
    link: 'decoration-none hover:text-foreground transition-colors-200 rounded-sm outline-none focus-visible:ring-3 focus-visible:ring-offset-background focus-visible:ring-primary/30'
  },
  variants: {
    size: {
      xs: {
        root: 'text-2xs',
        list: 'gap-2',
        item: 'gap-1.5'
      },
      sm: {
        root: 'text-xs',
        list: 'gap-2.5',
        item: 'gap-1.75'
      },
      md: {
        root: 'text-sm',
        list: 'gap-3',
        item: 'gap-2'
      },
      lg: {
        root: 'text-base',
        list: 'gap-3.5',
        item: 'gap-2.5'
      },
      xl: {
        root: 'text-lg',
        list: 'gap-4',
        item: 'gap-3'
      },
      '2xl': {
        root: 'text-xl',
        list: 'gap-4.5',
        item: 'gap-3.5'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
